import request from '@/utils/request'

/**
 * 分页列表
 */
export function getOperatorList(params) {
  return request({
    url: '/api/operator',
    method: 'get',
    params,
  })
}

/**
 * 详情
 */
export function getOperator(id) {
  return request({
    url: `/api/operator/${id}`,
    method: 'get',
  })
}

/**
 * 创建
 */
export function createOperator(data) {
  return request({
    url: '/api/operator',
    method: 'post',
    data,
  })
}

/**
 * 更新
 */
export function updateOperator(id, data) {
  return request({
    url: `/api/operator/${id}`,
    method: 'put',
    data,
  })
}

/**
 * 删除
 */
export function deleteOperator(id) {
  return request({
    url: `/api/operator/${id}`,
    method: 'delete',
  })
}
